        private static async Task<FilterRequest> ParseRequest(HttpRequest req, string tableName,
            HashSet<string> tableColumns)
        {
            var filterRequest = new FilterRequest();

            // Parse select columns
            var selectParam = req.Query["select"].FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(selectParam))
            {
                var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries);
                foreach (var col in requestedColumns)
                {
                    var trimmed = col.Trim();
                    if (tableColumns.Contains(trimmed))
                    {
                        filterRequest.SelectColumns.Add(trimmed);
                    }
                    else
                    {
                        filterRequest.Errors.Add($"Column '{trimmed}' is not a valid column for table '{tableName}'.");
                    }
                }
            }

            // Parse order by
            var orderByParam = req.Query["orderby"].FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(orderByParam))
            {
                var trimmed = orderByParam.Trim();
                if (tableColumns.Contains(trimmed))
                {
                    filterRequest.OrderByColumn = trimmed;
                }
                else
                {
                    filterRequest.Errors.Add($"OrderBy column '{trimmed}' is not valid for table '{tableName}'.");
                }
            }

            var orderParam = req.Query["order"].FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(orderParam))
            {
                if (AllowedSortDirections.Contains(orderParam.Trim()))
                {
                    filterRequest.SortDirection = orderParam.Trim().ToUpperInvariant();
                }
                else
                {
                    filterRequest.Errors.Add("Sort direction must be 'ASC' or 'DESC'.");
                }
            }

            // Parse top / offset
            var topParam = req.Query["top"].FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(topParam))
            {
                if (int.TryParse(topParam, out int topValue) && topValue > 0 && topValue <= 10000)
                {
                    filterRequest.Top = topValue;
                }
                else
                {
                    filterRequest.Errors.Add("'top' must be a positive integer no greater than 10000.");
                }
            }

            var offsetParam = req.Query["offset"].FirstOrDefault();
            if (!string.IsNullOrWhiteSpace(offsetParam))
            {
                if (int.TryParse(offsetParam, out int offsetValue) && offsetValue >= 0)
                {
                    filterRequest.Offset = offsetValue;
                }
                else
                {
                    filterRequest.Errors.Add("'offset' must be a non-negative integer.");
                }
            }

            // Parse filters from query string: filter_{column}_{operator}=value
            foreach (var key in req.Query.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                var parts = key.Split('_', 3);
                if (parts.Length != 3)
                {
                    filterRequest.Errors.Add($"Invalid filter format: '{key}'. Expected format: filter_Column_Operator");
                    continue;
                }

                var columnName = parts[1].Trim();
                var operatorAlias = parts[2].Trim();
                var value = req.Query[key].FirstOrDefault();

                if (!tableColumns.Contains(columnName))
                {
                    filterRequest.Errors.Add($"Column '{columnName}' is not valid for table '{tableName}'.");
                    continue;
                }

                if (!AllowedOperators.TryGetValue(operatorAlias, out var sqlOperator))
                {
                    filterRequest.Errors.Add(
                        $"Operator '{operatorAlias}' is not valid. Allowed: {string.Join(", ", AllowedOperators.Keys)}");
                    continue;
                }

                if (string.IsNullOrEmpty(value))
                {
                    filterRequest.Errors.Add($"Filter value for '{key}' cannot be empty.");
                    continue;
                }

                filterRequest.Filters.Add(new FilterCondition
                {
                    Column = columnName,
                    OperatorAlias = operatorAlias,
                    SqlOperator = sqlOperator,
                    Value = value
                });
            }

            // Also support POST body with JSON filters
            if (req.Method.Equals("POST", StringComparison.OrdinalIgnoreCase) &&
                req.ContentType?.Contains("application/json", StringComparison.OrdinalIgnoreCase) == true)
            {
                try
