                                filterRequest.Errors.Add(
                                    $"Column '{f.Column}' is not valid for table '{tableName}'.");
                                continue;
                            }

                            if (!AllowedOperators.TryGetValue(f.Operator, out var sqlOp))
                            {
                                filterRequest.Errors.Add(
