                                continue;
                            }

                            if (string.IsNullOrEmpty(f.Value))
                            {
                                filterRequest.Errors.Add($"Filter value for column '{f.Column}' cannot be empty.");
                                continue;
                            }

                            filterRequest.Filters.Add(new FilterCondition
                            {
                                Column = f.Column,
                                OperatorAlias = f.Operator,
                                SqlOperator = sqlOp,
                                Value = f.Value
                            });
                        }
                    }
                }
                catch (JsonException)
