        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string connectionString,
            string tableName,
            FilterRequest filterRequest,
            ILogger log)
        {
            var queryBuilder = new StringBuilder();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            // SELECT clause - columns are validated against whitelist so safe to use directly
            if (filterRequest.SelectColumns.Any())
            {
                var columns = string.Join(", ",
                    filterRequest.SelectColumns.Select(c => $"[{c}]"));
                queryBuilder.Append($"SELECT {columns}");
            }
            else
            {
                queryBuilder.Append("SELECT *");
            }

            // FROM clause - table name is validated against whitelist
            queryBuilder.Append($" FROM [{tableName}]");

            // WHERE clause - all values are parameterized
            if (filterRequest.Filters.Any())
            {
                queryBuilder.Append(" WHERE ");
                var conditions = new List<string>();

                foreach (var filter in filterRequest.Filters)
                {
                    // Column name is validated against whitelist, so bracket-quoting is safe
                    if (filter.SqlOperator == "IN")
                    {
                        var inValues = filter.Value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                        var inParams = new List<string>();

                        foreach (var val in inValues)
                        {
                            var paramName = $"@p{paramIndex++}";
                            inParams.Add(paramName);
                            parameters.Add(new SqlParameter(paramName, val.Trim()));
                        }

                        conditions.Add($"[{filter.Column}] IN ({string.Join(", ", inParams)})");
                    }
                    else
                    {
                        var paramName = $"@p{paramIndex++}";
                        conditions.Add($"[{filter.Column}] {filter.SqlOperator} {paramName}");
                        parameters.Add(new SqlParameter(paramName, filter.Value));
                    }
                }

                queryBuilder.Append(string.Join(" AND ", conditions));
            }

            // ORDER BY clause - column validated against whitelist, direction validated against enum
            if (!string.IsNullOrEmpty(filterRequest.OrderByColumn))
            {
                queryBuilder.Append($" ORDER BY [{filterRequest.OrderByColumn}] {filterRequest.SortDirection}");
            }
            else
            {
                // Required for OFFSET/FETCH
                queryBuilder.Append(" ORDER BY (SELECT NULL)");
            }

            // OFFSET / FETCH for pagination
            queryBuilder.Append(" OFFSET @offset ROWS");
            parameters.Add(new SqlParameter("@offset", filterRequest.Offset));

            queryBuilder.Append(" FETCH NEXT @top ROWS ONLY");
            parameters.Add(new SqlParameter("@top", filterRequest.Top));

            var sql = queryBuilder.ToString();
            log.LogInformation("Executing parameterized query: {Query} with {ParamCount} parameters",
                sql, parameters.Count);

            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(sql, connection))
                {
                    command.CommandTimeout = 30;
                    command.Parameters.AddRange(parameters.ToArray());

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var columns = Enumerable.Range(0, reader.FieldCount)
                            .Select(i => reader.GetName(i))
                            .ToList();

                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            foreach (var column in columns)
                            {
                                var value = reader[column];
                                row[column] = value == DBNull.Value ? null : value;
                            }

                            results.Add(row);
                        }
                    }
                }
            }

            return results;
        }
    }

